class Dog {
  private int age;

  Dog(int a) {
    age = a;
  }

  // GETTER: Public door to read the private age
  public int getAge() {
    return age;
  }
}

class Main {
  public static void main(String[] args) {
    Dog d = new Dog(5);
    // Correct way to read the data safely:
    System.out.println(d.getAge());
  }
}

class BankAccount {
  private double balance = 100.0;

  // SETTER: Only updates balance if the rules are followed
  public void setBalance(double newBalance) {
    if (newBalance >= 0) {
      this.balance = newBalance;
    } else {
      System.out.println("Error: Balance cannot be negative!");
    }
  }
}
